<div class="col-lg-8"><div class="card p-4"><div class="d-flex justify-content-between mb-3"><h2 class="h6">Laundry Items</h2><button type="button" id="addItem" class="btn btn-outline-success btn-sm">Add Item</button></div><div id="items"><div class="row g-2 item-row mb-2"><div class="col-md-5"><input name="items[0][item_name]" class="form-control" placeholder="Item name" required></div><div class="col-md-3"><input type="number" name="items[0][quantity]" class="form-control qty" value="1" min="1" required></div><div class="col-md-3"><input type="number" step="0.1" name="items[0][weight_kg]" class="form-control weight" value="1" min="0.1" required></div><div class="col-md-1"><button type="button" class="btn btn-outline-danger w-100 remove">x</button></div></div></div></div></div>
